// Script Continued Below
// dtechMouseOver
// Use this service to hover over items in gojs or other angularjs capabilities
// For example, given the following string, get the first 5 readable characters

function dtechMouseOver($document, $timeout) {
	var CONST_TOOLTIP_DURATION = 4900;
	var CONST_PARENT_WAIT_DURATION = 200;
	var CONST_PROFILE_ADJUST_LEFT = -190;
	var self = this;
	var openScope = null;
	var openTimeout = null;

	var cancelTimeout = _cancelTimeout;
	var close = _close;
	var closeToolTip = _closeToolTip;
	var escapeKeyBind = _escapeKeyBind;
	var open = _open;
	var parentMouseLeave = _parentMouseLeave;
	var setLocation = _setLocation;
	var setTimeout = _setTimeout;
	return {
		cancelTimeout: cancelTimeout,
		close: close,
		open: open,
		parentMouseLeave: parentMouseLeave
	};

	function _cancelTimeout(){
		if(openTimeout){
			$timeout.cancel(openTimeout);
			openTimeout = null;
		}
	}

	function _close(closeScope){
		if(openScope && openScope===closeScope) {
			// clear the profile object
			openScope.dtechUserProfile={};
			// clear parentMouseLeave
			openScope.parentMouseLeave=false;
			// clear the scope
      openScope = null;
      $document.unbind('click', closeToolTip);
      $document.unbind('keydown', escapeKeyBind);
			$document.unbind('scroll', closeToolTip);
			_cancelTimeout();
    }
	}

	function _closeToolTip() {
		// ignore if scope already cleared
		if(openScope){
			openScope.$apply(function() {
				openScope.isOpen = false;
			});
		}
	}

  function _escapeKeyBind(evt) {
    if ( evt.which === 27 ) {
      _closeToolTip();
    }
  }

	function _setLocation(){
		if(openScope && openScope.dtechProfileLocation){
			var locationPt = openScope.dtechProfileLocation;
			var popoverDiv = angular.element(document.getElementById('dtechUserProfile'))[0];
			var adjustLeft = CONST_PROFILE_ADJUST_LEFT;

			// Do not go left of the viewport edge
			if (locationPt.x + adjustLeft <= 0) {
				adjustLeft = -10;
			}

			// TODO - change left most postion position so pointer looks right
			// TODO -	set pointer differntly than tooltip
			popoverDiv.style.left = Math.ceil(locationPt.x + adjustLeft) + "px";
			popoverDiv.style.top = Math.ceil(locationPt.y + 100) + "px";
		}
	}

	function _open(newScope){
		if(!openScope){
      $document.bind('click', closeToolTip);
      $document.bind('keydown', escapeKeyBind);			
			$document.bind('scroll', closeToolTip);
		}

		if(openScope && openScope !== newScope){
			// a tooltip is open, but it isn't the current tooltip
			// close the current tooltip and cancel the timeout
			openScope.isOpen = false;
			_cancelTimeout();
			// let the other instance open it's tooltip
		}

		// set the scope to the new scope
		openScope = newScope;
		// show the tooltip on the new scope
		openScope.isOpen = true;
		// set location
		setLocation();
		// set the timout for the tooltip
		setTimeout();

	}

	// wait to see if the user is trying to move mouse over profile
	// if not over profile, then close
	function _parentMouseLeave(localScope){
		if(openScope===localScope) {
			// if mouse leaving parent wait to see if goes over profile
			$timeout(
				function() {
					// after delay if not over profile, then close
					if(!openScope || !openScope.isOverProfile){
						_closeToolTip();
					}
			}, CONST_PARENT_WAIT_DURATION);


    }
	}

	function _setTimeout(){
		openTimeout = $timeout(function() {
			openScope.isOpen = false;
			openTimeout = null;
		}, CONST_TOOLTIP_DURATION);
	}

}
